// JavaScript executes from top to bottom, one statement at a time.
// Lines beginning with // are single-line comments — JavaScript ignores them.

/* This is a multi-line comment.
   It spans as many lines as needed. */

// console.log() displays output in the console.
console.log("Hello, World!");

// You can log any value: strings, numbers, booleans.
console.log("JavaScript was created in 1995.");
console.log(42);
console.log(true);

// console.log() accepts multiple arguments — prints them separated by spaces.
console.log("Years since creation:", 2025 - 1995);

// The semicolon ; ends a statement. It is optional but recommended.
console.log("Semicolons end statements");

