codeExample.code:
// Cinema ticket booking — let and const in action

// Constants: values that will never change
const TICKET_PRICE   = 200;    // price in rupees
const MAX_SEATS      = 100;    // total seats in the hall
const MOVIE_TITLE    = "Dune: Part Three";

// Variables: values that will change as tickets are sold
let seatsBooked  = 0;
let totalRevenue = 0;

// Simulate booking 3 tickets
seatsBooked  += 3;
totalRevenue  = seatsBooked * TICKET_PRICE;

console.log("Movie:",         MOVIE_TITLE);
console.log("Seats booked:",  seatsBooked);
console.log("Seats left:",    MAX_SEATS - seatsBooked);
console.log("Revenue (₹):",   totalRevenue);

// let allows reassignment
let customerName = "Ananya";
console.log("Booked by:", customerName);
customerName = "Rahul";          // change the name
console.log("Updated to:", customerName);

